    # CTA
    h += f'<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="padding:24px 22px 20px;text-align:center;"><p style="margin:0 0 12px;font-size:17px;font-weight:700;color:{B["ink"]};line-height:1.5;">If this sounds familiar, keep reading.</p><p style="margin:0 0 24px;font-size:15px;color:{B["soft"]};line-height:1.6;">We\'ll send you more over the next few days, what the science says, what other parents found, and how you can try the Body-Signal approach.</p>{cta("#","See How It Works",fs=18,pv=17,ph=32,w=280)}<p style="margin:20px 0 0;font-size:14px;color:{B["muted"]};font-style:italic;">Next time: Why the methods you tried couldn\'t work {MUL} and what actually can.</p></td></tr></table>'
